#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=10000005;
ll n,p[N],top,l[N],r[N],ans1,ans2;
stack<int> st;
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n;
	for(int i=1;i<=n;i++)
	{
		cin>>p[i];
		bool flag=0;
		int lst;
		while(!st.empty()&&p[st.top()]>p[i])
		{
			lst=st.top();
			st.pop();
			flag=1;
		}
		if(!st.empty()) r[st.top()]=i;
		if(flag) l[i]=lst;
		st.push(i);
	}
	for(int i=1;i<=n;i++)
	{
		ans1^=(i*(l[i]+1));
		ans2^=(i*(r[i]+1));
	}
	cout<<ans1<<" "<<ans2<<"\n";
	return 0;
}
